namespace sv_c9ae528fe9d040e6a373ed9251d2fecf.Client.Models;

public sealed record Shipment(
    string TrackingNumber,
    string Status,
    string Location,
    DateTimeOffset EstimatedDelivery,
    IReadOnlyList<StatusUpdate> StatusUpdates);

public sealed record StatusUpdate(
    DateTimeOffset Timestamp,
    string Description,
    string Location);

using sv_c9ae528fe9d040e6a373ed9251d2fecf.Client.Models;

namespace sv_c9ae528fe9d040e6a373ed9251d2fecf.Client.Services;

public interface IShipmentService
{
    Task<Shipment?> GetShipmentAsync(string trackingNumber, CancellationToken ct);
}

using sv_c9ae528fe9d040e6a373ed9251d2fecf.Client.Models;
using sv_c9ae528fe9d040e6a373ed9251d2fecf.Client.Services;

namespace sv_c9ae528fe9d040e6a373ed9251d2fecf.Services;

public sealed class ShipmentService : IShipmentService
{
    private static readonly Dictionary<string, Shipment> SeedData = new(StringComparer.OrdinalIgnoreCase)
    {
        ["TRK-001"] = new Shipment(
            "TRK-001",
            "In Transit",
            "Memphis, TN",
            new DateTimeOffset(2026, 6, 2, 17, 0, 0, TimeSpan.Zero),
            [
                new StatusUpdate(new DateTimeOffset(2026, 5, 23, 9, 0, 0, TimeSpan.Zero), "Package picked up", "New York, NY"),
                new StatusUpdate(new DateTimeOffset(2026, 5, 24, 14, 30, 0, TimeSpan.Zero), "Arrived at sorting facility", "Memphis, TN"),
                new StatusUpdate(new DateTimeOffset(2026, 5, 25, 8, 15, 0, TimeSpan.Zero), "In transit to destination", "Memphis, TN"),
            ]),
        ["TRK-002"] = new Shipment(
            "TRK-002",
            "Delivered",
            "Seattle, WA",
            new DateTimeOffset(2026, 5, 25, 12, 0, 0, TimeSpan.Zero),
            [
                new StatusUpdate(new DateTimeOffset(2026, 5, 20, 10, 0, 0, TimeSpan.Zero), "Package picked up", "Los Angeles, CA"),
                new StatusUpdate(new DateTimeOffset(2026, 5, 21, 16, 45, 0, TimeSpan.Zero), "Arrived at sorting facility", "Portland, OR"),
                new StatusUpdate(new DateTimeOffset(2026, 5, 22, 11, 0, 0, TimeSpan.Zero), "Out for delivery", "Seattle, WA"),
                new StatusUpdate(new DateTimeOffset(2026, 5, 22, 14, 20, 0, TimeSpan.Zero), "Delivered — signed by J. Smith", "Seattle, WA"),
            ]),
        ["TRK-003"] = new Shipment(
            "TRK-003",
            "Processing",
            "Chicago, IL",
            new DateTimeOffset(2026, 6, 5, 18, 0, 0, TimeSpan.Zero),
            [
                new StatusUpdate(new DateTimeOffset(2026, 5, 25, 20, 0, 0, TimeSpan.Zero), "Label created", "Chicago, IL"),
            ]),
    };

    public async Task<Shipment?> GetShipmentAsync(string trackingNumber, CancellationToken ct)
    {
        await Task.Delay(1500, ct);
        SeedData.TryGetValue(trackingNumber, out var shipment);
        return shipment;
    }
}

@page "/shipments/{TrackingNumber}"
@rendermode InteractiveAuto
@using sv_c9ae528fe9d040e6a373ed9251d2fecf.Client.Models
@using sv_c9ae528fe9d040e6a373ed9251d2fecf.Client.Services
@inject IShipmentService ShipmentService
@inject ILogger<ShipmentTracker> Logger
@implements IDisposable

<PageTitle>Shipment @TrackingNumber</PageTitle>

@if (_loading)
{
    <div class="shipment-loading">
        <p><em>Loading shipment @TrackingNumber…</em></p>
    </div>
}
else if (_errorMessage is not null)
{
    <div class="shipment-error">
        <p>@_errorMessage</p>
        <button @onclick="RetryAsync">Retry</button>
    </div>
}
else if (_shipment is null)
{
    <div class="shipment-not-found">
        <p>No shipment found for tracking number <strong>@TrackingNumber</strong>.</p>
    </div>
}
else
{
    <div class="shipment-details">
        <h2>Shipment @_shipment.TrackingNumber</h2>
        <dl>
            <dt>Status</dt>
            <dd>@_shipment.Status</dd>
            <dt>Location</dt>
            <dd>@_shipment.Location</dd>
            <dt>Estimated Delivery</dt>
            <dd>@_shipment.EstimatedDelivery.ToString("f")</dd>
        </dl>

        <h3>Tracking History</h3>
        <table>
            <thead>
                <tr>
                    <th>Time</th>
                    <th>Description</th>
                    <th>Location</th>
                </tr>
            </thead>
            <tbody>
                @foreach (var update in _shipment.StatusUpdates)
                {
                    <tr>
                        <td>@update.Timestamp.ToString("g")</td>
                        <td>@update.Description</td>
                        <td>@update.Location</td>
                    </tr>
                }
            </tbody>
        </table>
    </div>
}

@code {
    [Parameter]
    public string TrackingNumber { get; set; } = string.Empty;

    private Shipment? _shipment;
    private bool _loading;
    private string? _errorMessage;

    private CancellationTokenSource? _cts;

    protected override async Task OnParametersSetAsync()
    {
        await LoadShipmentAsync();
    }

    private async Task LoadShipmentAsync()
    {
        // Cancel any in-flight request before starting a new one.
        CancelPending();

        _shipment = null;
        _errorMessage = null;
        _loading = true;
        StateHasChanged();

        var cts = new CancellationTokenSource();
        _cts = cts;

        try
        {
            _shipment = await ShipmentService.GetShipmentAsync(TrackingNumber, cts.Token);
        }
        catch (OperationCanceledException)
        {
            // Request was intentionally cancelled — do nothing.
            return;
        }
        catch (TimeoutException)
        {
            Logger.LogError("Timeout while loading shipment {TrackingNumber}", TrackingNumber);
            _errorMessage = "The request timed out. Please try again.";
        }
        catch (Exception ex)
        {
            Logger.LogError(ex, "Error loading shipment {TrackingNumber}", TrackingNumber);
            _errorMessage = "Something went wrong while loading the shipment. Please try again.";
        }
        finally
        {
            // Only update UI if this CTS is still the current one (not superseded).
            if (_cts == cts)
            {
                _loading = false;
                StateHasChanged();
            }
        }
    }

    private async Task RetryAsync()
    {
        await LoadShipmentAsync();
    }

    private void CancelPending()
    {
        _cts?.Cancel();
        _cts?.Dispose();
        _cts = null;
    }

    public void Dispose()
    {
        CancelPending();
    }
}

